script:
frappe.ui.form.on('Quotation', {
    // 1. The trigger must exactly match the dropdown fieldname
    custom_sow_template: function(frm) {

        // 2. Check the custom fieldname
        if (frm.doc.custom_sow_template) {

            frappe.show_alert({message: 'Fetching Template...', indicator: 'blue'});

            // 3. Fetch using the custom fieldname
            frappe.model.with_doc('Scope of Work Template', frm.doc.custom_sow_template, function() {
                let template_doc = frappe.get_doc('Scope of Work Template', frm.doc.custom_sow_template);

                // 4. Clear the custom table
                frm.clear_table('custom_scope_of_work_tasks');

                // Note: scope_of_work_details likely DOES NOT have a custom_ prefix 
                // because you built it directly in a new DocType, not Customize Form!
                if (template_doc && template_doc.scope_of_work_details) {
                    template_doc.scope_of_work_details.forEach(row => {

                        // 5. Add to the custom table
                        let child = frm.add_child('custom_scope_of_work_tasks');
                        child.task_description = row.task_description;
                        child.in_scope = row.in_scope;
                    });

                    // 6. Refresh the custom table
                    frm.refresh_field('custom_scope_of_work_tasks');
                    frappe.msgprint(`Successfully loaded ${frm.doc.custom_sow_template} checklist!`);
                }
            });
        }
    }
});
